### Checking for Prime Numbers in an Array

Here's a JavaScript function that checks if any of the numbers in an array is a valid prime number.

```javascript
function isPrime(n) {
    if (n < 2) {
        return false;
    }
    for (let i = 2; i < n; i++) {
        if (n % i === 0) {
            return false;
        }
    }
    return true;
}

function checkPrimeNumbers(array) {
    const primeNumbers = [];

    if (array.length!== 5) {
        console.log("The array must have 5 numbers.");
    } else {
        for (const number of array) {
            if (typeof number!== "number" || number < 0) {
                console.log("The array must only contain positive integers.");
                return;
            }

            if (isPrime(number)) {
                primeNumbers.push(number);
            }
        }
        console.log("Valid prime numbers in the array:");
        console.log(primeNumbers);
    }
}

// Example usage:
const array = [12, 25, 30, 51, 23];
checkPrimeNumbers(array);
```

